static void uart_init(uint32_t baudrate)
{
    /* Enable GPIOA clock (USART2 TX=PA2, RX=PA3) */
    RCC_AHB1ENR |= (1U << 0);
    /* Enable USART2 clock */
    RCC_APB1ENR |= (1U << 17);

    /* Configure PA2 (TX) and PA3 (RX) as Alternate Function (AF7 = USART2) */
    /* PA2: MODER = AF (10) */
    GPIOA->MODER &= ~(3U << (2 * 2));
    GPIOA->MODER |=  (2U << (2 * 2));
    /* PA3: MODER = AF (10) */
    GPIOA->MODER &= ~(3U << (3 * 2));
    GPIOA->MODER |=  (2U << (3 * 2));

    /* Set AF7 for PA2 and PA3 */
    GPIOA->AFRL &= ~(0xFU << (2 * 4));
    GPIOA->AFRL |=  (7U << (2 * 4));
    GPIOA->AFRL &= ~(0xFU << (3 * 4));
    GPIOA->AFRL |=  (7U << (3 * 4));

    /* High speed for TX pin */
    GPIOA->OSPEEDR |= (3U << (2 * 2));

    /* Pull-up on RX pin */
    GPIOA->PUPDR &= ~(3U << (3 * 2));
    GPIOA->PUPDR |=  (1U << (3 * 2));

    /* Configure USART2 */
    USART2->CR1 = 0;  /* Reset CR1 */
    USART2->CR2 = 0;  /* 1 stop bit */
    USART2->CR3 = 0;  /* No flow control */

    /* Set baud rate: BRR = fCLK / baudrate */
    /* APB1 clock = 42 MHz (assuming 84MHz system, APB1 prescaler = 2) */
    uint32_t apb1_clock = SYSTEM_CLOCK_HZ / 2;  /* 42 MHz */
    uint32_t usart_div = (apb1_clock + baudrate / 2) / baudrate;
    USART2->BRR = usart_div;

    /* Enable USART: TX, RX, USART enable */
    USART2->CR1 = USART_CR1_TE | USART_CR1_RE | USART_CR1_UE;
}

static void uart_send_char(char c)
{
    while (!(USART2->SR & USART_SR_TXE))
        ;
    USART2->DR = (uint32_t)c;
}

static void uart_send_string(const char *str)
{
    while (*str) {
        if (*str == '\n') {
            uart_send_char('\r');
        }
        uart_send_char(*str++);
    }
}

static void uart_send_hex(uint32_t value, uint8_t digits)
{
    static const char hex_chars[] = "0123456789ABCDEF";
    for (int i = (digits - 1) * 4; i >= 0; i -= 4) {
        uart_send_char(hex_chars[(value >> i) & 0xF]);
    }
}

static void uart_send_hex8(uint8_t value)
{
    uart_send_hex(value, 2);
}

static void uart_send_decimal(int32_t value)
{
    char buf[12];
    int i = 0;
    bool negative = false;

    if (value < 0) {
        negative = true;
        value = -value;
    }

    if (value == 0) {
        uart_send_char('0');
        return;
    }

    while (value > 0 && i < 11) {
        buf[i++] = '0' + (value % 10);
        value /= 10;
    }

    if (negative) {
        uart_send_char('-');
    }

    while (i > 0) {
        uart_send_char(buf[--i]);
    }
}

static void uart_send_float(float value, uint8_t decimals)
{
    if (value < 0) {
        uart_send_char('-');
        value = -value;
    }

    int32_t integer_part = (int32_t)value;
    uart_send_decimal(integer_part);
    uart_send_char('.');

    float frac = value - (float)integer_part;
    for (uint8_t i = 0; i < decimals; i++) {
        frac *= 10.0f;
        int digit = (int)frac;
        uart_send_char('0' + digit);
        frac -= digit;
    }
}

static bool uart_char_available(void)
{
    return (USART2->SR & USART_SR_RXNE) != 0;
}

static char uart_get_char(void)
{
    while (!uart_char_available())
        ;
    return (char)(USART2->DR & 0xFF);
}

static int uart_receive_char_timeout(uint32_t timeout_ms)
{
    uint32_t start = get_system_uptime_ms();
    while ((get_system_uptime_ms() - start) < timeout_ms) {
        if (uart_char_available()) {
            return (int)(USART2->DR & 0xFF);
        }
    }
    return -1;  /* Timeout */
}

