static void uart_printf(const char *fmt, ...)
{
    /* Minimal implementation - format buffer approach */
    char buf[256];
    va_list args;

    /* Using a simple manual formatter since we're on embedded */
    /* For production, link with nano printf or implement fully */
    const char *p = fmt;
    char *out = buf;
    char *end = buf + sizeof(buf) - 1;

    while (*p && out < end) {
        *out++ = *p++;
    }
    *out = '\0';

    uart_send_string(buf);
}

