static void jtag_pins_init(void)
{
    /* Enable GPIOA and GPIOB clocks */
    RCC_AHB1ENR |= (1U << 0) | (1U << 1);

    /* By default after reset, JTAG pins are in their debug AF mode.
     * We configure based on desired debug access level. */
}

static void jtag_enable_full(void)
{
    /* Enable both JTAG and SWD interfaces */
    /* PA13=SWDIO, PA14=SWCLK, PA15=JTDI, PB3=JTDO, PB4=JTRST */

    RCC_AHB1ENR |= (1U << 0) | (1U << 1);

    /* Set PA13, PA14, PA15 to AF mode (JTAG/SWD) */
    GPIOA->MODER &= ~((3U << (13 * 2)) | (3U << (14 * 2)) | (3U << (15 * 2)));
    GPIOA->MODER |=  ((2U << (13 * 2)) | (2U << (14 * 2)) | (2U << (15 * 2)));

    /* Set PB3, PB4 to AF mode (JTAG) */
    GPIOB->MODER &= ~((3U << (3 * 2)) | (3U << (4 * 2)));
    GPIOB->MODER |=  ((2U << (3 * 2)) | (2U << (4 * 2)));

    /* AF0 for JTAG/SWD pins */
    /* PA13 AF0 */
    GPIOA->AFRH &= ~(0xFU << ((13 - 8) * 4));
    /* PA14 AF0 */
    GPIOA->AFRH &= ~(0xFU << ((14 - 8) * 4));
    /* PA15 AF0 */
    GPIOA->AFRH &= ~(0xFU << ((15 - 8) * 4));
    /* PB3 AF0 */
    GPIOB->AFRL &= ~(0xFU << (3 * 4));
    /* PB4 AF0 */
    GPIOB->AFRL &= ~(0xFU << (4 * 4));

    /* Enable debug in low-power modes */
    DBGMCU_CR |= (1U << 0) | (1U << 1) | (1U << 2);  /* DBG_SLEEP, DBG_STOP, DBG_STANDBY */

    uart_send_string("[JTAG] Full JTAG+SWD interface enabled\n");
    uart_send_string("[JTAG] Pins: PA13(SWDIO) PA14(SWCLK) PA15(JTDI) PB3(JTDO) PB4(JTRST)\n");
}

static void jtag_enable_swd_only(void)
{
    /* Enable only SWD (2-wire), release JTAG pins for GPIO use */

    RCC_AHB1ENR |= (1U << 0) | (1U << 1);

    /* PA13=SWDIO, PA14=SWCLK remain in AF mode */
    GPIOA->MODER &= ~((3U << (13 * 2)) | (3U << (14 * 2)));
    GPIOA->MODER |=  ((2U << (13 * 2)) | (2U << (14 * 2)));

    /* Release PA15, PB3, PB4 as GPIO inputs */
    GPIOA->MODER &= ~(3U << (15 * 2));  /* PA15 = input */
    GPIOB->MODER &= ~((3U << (3 * 2)) | (3U << (4 * 2)));  /* PB3, PB4 = input */

    /* Enable debug in low-power modes */
    DBGMCU_CR |= (1U << 0) | (1U << 1) | (1U << 2);

    uart_send_string("[JTAG] SWD-only mode enabled (PA13=SWDIO, PA14=SWCLK)\n");
    uart_send_string("[JTAG] PA15, PB3, PB4 released for GPIO use\n");
}

static void jtag_disable(void)
{
    /* Disable all debug interfaces - release all pins */
    /* WARNING: This will prevent debugger connection until next reset */

    /* Set all JTAG/SWD pins to GPIO input mode */
    GPIOA->MODER &= ~((3U << (13 * 2)) | (3U << (14 * 2)) | (3U << (15 * 2)));
    GPIOB->MODER &= ~((3U << (3 * 2)) | (3U << (4 * 2)));

    /* Disable debug in low-power modes */
    DBGMCU_CR &= ~((1U << 0) | (1U << 1) | (1U << 2));

    uart_send_string("[JTAG] All debug interfaces DISABLED\n");
    uart_send_string("[JTAG] WARNING: Debugger cannot connect until next reset\n");
}

