static uint32_t crc32_compute(const uint8_t *data, uint32_t length)
{
    uint32_t crc = 0xFFFFFFFF;
    for (uint32_t i = 0; i < length; i++) {
        crc ^= data[i];
        for (int j = 0; j < 8; j++) {
            if (crc & 1)
                crc = (crc >> 1) ^ 0xEDB88320;
            else
                crc >>= 1;
        }
    }
    return ~crc;
}

static uint32_t config_calc_crc(const device_config_t *cfg)
{
    /* CRC over everything except magic, version, and crc fields */
    const uint8_t *data = (const uint8_t *)cfg + offsetof(device_config_t, device_id);
    uint32_t len = sizeof(device_config_t) - offsetof(device_config_t, device_id);
    return crc32_compute(data, len);
}

