static void cmd_help(int argc, char *argv[])
{
    if (argc > 1) {
        /* Show detailed help for specific command */
        for (int i = 0; g_commands[i].name != NULL; i++) {
            if (strcmp(argv[1], g_commands[i].name) == 0) {
                uart_send_string("Command: ");
                uart_send_string(g_commands[i].name);
                uart_send_string("\nUsage:   ");
                uart_send_string(g_commands[i].usage);
                uart_send_string("\nInfo:    ");
                uart_send_string(g_commands[i].description);
                if (g_commands[i].requires_auth) {
                    uart_send_string("\n         [Requires authentication]");
                }
                uart_send_string("\n");
                return;
            }
        }
        uart_send_string("Unknown command: ");
        uart_send_string(argv[1]);
        uart_send_string("\n");
        return;
    }

    uart_send_string("\nAvailable Commands:\n");
    uart_send_string("-------------------------------------------\n");

    for (int i = 0; g_commands[i].name != NULL; i++) {
        uart_send_string("  ");
        uart_send_string(g_commands[i].name);

        /* Padding for alignment */
        int pad = 16 - (int)strlen(g_commands[i].name);
        while (pad-- > 0) uart_send_char(' ');

        uart_send_string(g_commands[i].description);

        if (g_commands[i].requires_auth && !g_authenticated) {
            uart_send_string(" [LOCKED]");
        }
        uart_send_string("\n");
    }

    uart_send_string("-------------------------------------------\n");
    if (!g_authenticated) {
        uart_send_string("Use 'auth <password>' to unlock privileged commands\n");
    }
}

static void cmd_auth(int argc, char *argv[])
{
#if AUTH_ENABLED
    if (g_authenticated) {
        uart_send_string("Already authenticated\n");
        return;
    }

    if (g_auth_attempts >= AUTH_MAX_ATTEMPTS) {
        uart_send_string("ERROR: Maximum authentication attempts exceeded\n");
        uart_send_string("Please reboot the device to retry\n");
        return;
    }

    if (argc < 2) {
        uart_send_string("Usage: auth <password>\n");
        return;
    }

    if (strcmp(argv[1], AUTH_PASSWORD) == 0) {
        g_authenticated = true;
        g_auth_attempts = 0;
        uart_send_string("Authentication successful. Privileged commands unlocked.\n");
    } else {
        g_auth_attempts++;
        uart_send_string("Authentication failed. Attempts remaining: ");
        uart_send_decimal(AUTH_MAX_ATTEMPTS - g_auth_attempts);
        uart_send_string("\n");
    }
#else
    g_authenticated = true;
    uart_send_string("Authentication disabled in this build\n");
#endif
}

static void cmd_logout(int argc, char *argv[])
{
    (void)argc;
    (void)argv;
    g_authenticated = false;
    uart_send_string("Logged out. Privileged commands locked.\n");
}

